import { useState, useEffect } from "react";

function OnboardingPage({ onNext }) {
  const [examsData, setExamsData] = useState([]);
  const [selectedExam, setSelectedExam] = useState(null);
  const [selectedSubjects, setSelectedSubjects] = useState([]);
  const [selectedTopics, setSelectedTopics] = useState({});
  const [currentStep, setCurrentStep] = useState("examSelection");
  const [hours, setHours] = useState(4);
  const [targetDate, setTargetDate] = useState("");
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    fetch("http://localhost:5001/api/exams")
      .then((res) => res.json())
      .then(setExamsData)
      .catch((err) => {
        console.error("Sınavları getirirken hata:", err);
        setExamsData([]);
      });
  }, []);

  const handleGenerateSchedule = async () => {
    setIsGenerating(true);
    setError("");

    try {
      const response = await fetch("http://localhost:5001/api/generate-schedule", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          exam: selectedExam?.name,
          subjects: selectedSubjects,
          topics: selectedTopics,
          hours,
          deadline: targetDate,
        }),
      });

      const data = await response.json();
      onNext(data);
    } catch (err) {
      console.error("Plan üretirken hata:", err);
      setError("Plan üretilemedi. Lütfen tekrar deneyin.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div>
      <h2>Plan Oluştur</h2>
      {error && <p style={{ color: "crimson" }}>{error}</p>}
      <button onClick={handleGenerateSchedule} disabled={isGenerating}>
        Plan Üret
      </button>
    </div>
  );
}

export default OnboardingPage;
